// 构建游戏评级查询SQL
const gameName = $node['Webhook触发'].json.body.game_name;

if (!gameName) {
  throw new Error('游戏名称不能为空');
}

// 计算30天前的日期
const thirtyDaysAgo = new Date();
thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
const startDate = thirtyDaysAgo.toISOString().split('T')[0];

return {
  json: {
    gameName: gameName,
    startDate: startDate,
    queries: [
      {
        key: "revenue",
        name: "收入数据",
        sql: `
          SELECT 
            SUM(amount) as total_revenue,
            COUNT(*) as transactions,
            COUNT(DISTINCT user_id) as paying_users,
            AVG(amount) as avg_transaction
          FROM transactions
          WHERE game_name = '${gameName}'
            AND DATE(transaction_date) >= DATE '${startDate}'
            AND status = 'success'
        `
      },
      {
        key: "activeUsers",
        name: "活跃用户",
        sql: `
          SELECT 
            COUNT(DISTINCT user_id) as total_active,
            COUNT(DISTINCT CASE WHEN activity_date >= CURRENT_DATE - INTERVAL '7' DAY THEN user_id END) as week_active,
            COUNT(DISTINCT CASE WHEN activity_date = CURRENT_DATE - INTERVAL '1' DAY THEN user_id END) as yesterday_active
          FROM user_activity
          WHERE game_name = '${gameName}'
            AND DATE(activity_date) >= DATE '${startDate}'
        `
      },
      {
        key: "retention",
        name: "留存率",
        sql: `
          WITH day1_users AS (
            SELECT DISTINCT user_id, activity_date
            FROM user_activity
            WHERE game_name = '${gameName}'
              AND DATE(activity_date) >= DATE '${startDate}'
          )
          SELECT 
            COUNT(DISTINCT a.user_id) as day1_users,
            COUNT(DISTINCT b.user_id) as day2_retained,
            CAST(COUNT(DISTINCT b.user_id) AS DOUBLE) / NULLIF(COUNT(DISTINCT a.user_id), 0) as retention_rate
          FROM day1_users a
          LEFT JOIN day1_users b 
            ON a.user_id = b.user_id 
            AND b.activity_date = a.activity_date + INTERVAL '1' DAY
        `
      },
      {
        key: "totalUsers",
        name: "总用户数",
        sql: `
          SELECT COUNT(DISTINCT user_id) as total_users
          FROM user_activity
          WHERE game_name = '${gameName}'
            AND DATE(activity_date) >= DATE '${startDate}'
        `
      }
    ]
  }
};

// 汇总所有查询结果
const items = $input.all();
const gameName = items[0].json.gameName;
const results = {};

for (const item of items) {
  const queryKey = item.json.key;
  const queryResult = item.json.apiResponse;

  if (queryResult && queryResult.success && queryResult.data.rows.length > 0) {
    results[queryKey] = queryResult.data.rows[0];
  } else {
    results[queryKey] = {};
  }
}

return {
  json: {
    gameName: gameName,
    data: results,
    queriedAt: new Date().toISOString()
  }
};

// 计算游戏评级
const { gameName, data } = $input.item.json;

// 评级函数
function getGradeAndScore(value, thresholds) {
  if (value >= thresholds.S) return { grade: 'S', score: 100, color: 'green', emoji: '🌟' };
  if (value >= thresholds.A) return { grade: 'A', score: 85, color: 'blue', emoji: '⭐' };
  if (value >= thresholds.B) return { grade: 'B', score: 70, color: 'orange', emoji: '✨' };
  if (value >= thresholds.C) return { grade: 'C', score: 50, color: 'yellow', emoji: '💫' };
  return { grade: 'D', score: 30, color: 'red', emoji: '⚡' };
}

// 提取数据
const revenue = parseFloat(data.revenue?.total_revenue) || 0;
const dau = parseInt(data.activeUsers?.yesterday_active) || 0;
const payingUsers = parseInt(data.revenue?.paying_users) || 0;
const totalUsers = parseInt(data.totalUsers?.total_users) || 1;
const payingRate = payingUsers / totalUsers;
const retentionRate = parseFloat(data.retention?.retention_rate) || 0;
const avgTransaction = parseFloat(data.revenue?.avg_transaction) || 0;

// 评级阈值
const revenueGrade = getGradeAndScore(revenue, {
  S: 10000000,  // 1000万
  A: 5000000,   // 500万
  B: 1000000,   // 100万
  C: 100000     // 10万
});

const activeGrade = getGradeAndScore(dau, {
  S: 100000,
  A: 50000,
  B: 10000,
  C: 1000
});

const payingGrade = getGradeAndScore(payingRate, {
  S: 0.1,   // 10%
  A: 0.05,  // 5%
  B: 0.02,  // 2%
  C: 0.005  // 0.5%
});

const retentionGrade = getGradeAndScore(retentionRate, {
  S: 0.5,   // 50%
  A: 0.3,   // 30%
  B: 0.15,  // 15%
  C: 0.05   // 5%
});

// 计算加权总分
const totalScore = Math.round(
  revenueGrade.score * 0.4 +
  activeGrade.score * 0.3 +
  payingGrade.score * 0.2 +
  retentionGrade.score * 0.1
);

// 确定最终评级
const finalGrade = getGradeAndScore(totalScore, {
  S: 90,
  A: 75,
  B: 60,
  C: 45
});

return {
  json: {
    gameName: gameName,
    rating: {
      finalGrade: finalGrade.grade,
      totalScore: totalScore,
      color: finalGrade.color,
      emoji: finalGrade.emoji
    },
    metrics: {
      revenue: {
        label: '💰 收入表现',
        value: `¥${(revenue / 10000).toFixed(2)}万`,
        rawValue: revenue,
        grade: revenueGrade.grade,
        score: revenueGrade.score,
        weight: '40%',
        emoji: revenueGrade.emoji
      },
      activeUsers: {
        label: '👥 用户活跃',
        value: `${dau.toLocaleString()}人`,
        rawValue: dau,
        grade: activeGrade.grade,
        score: activeGrade.score,
        weight: '30%',
        emoji: activeGrade.emoji
      },
      payingRate: {
        label: '💳 付费率',
        value: `${(payingRate * 100).toFixed(2)}%`,
        rawValue: payingRate,
        grade: payingGrade.grade,
        score: payingGrade.score,
        weight: '20%',
        emoji: payingGrade.emoji
      },
      retention: {
        label: '🔄 次日留存',
        value: `${(retentionRate * 100).toFixed(2)}%`,
        rawValue: retentionRate,
        grade: retentionGrade.grade,
        score: retentionGrade.score,
        weight: '10%',
        emoji: retentionGrade.emoji
      }
    },
    additionalInfo: {
      transactions: parseInt(data.revenue?.transactions) || 0,
      payingUsers: payingUsers,
      totalUsers: totalUsers,
      avgTransaction: avgTransaction
    },
    generatedAt: new Date().toISOString()
  }
};

// 生成Lark卡片消息
const { gameName, rating, metrics, additionalInfo, generatedAt } = $input.item.json;

// 构建卡片内容
const card = {
  "config": {
    "wide_screen_mode": true
  },
  "header": {
    "template": rating.color,
    "title": {
      "content": `${rating.emoji} ${gameName} - 游戏评级报告`,
      "tag": "plain_text"
    }
  },
  "elements": [
    {
      "tag": "div",
      "fields": [
        {
          "is_short": true,
          "text": {
            "tag": "lark_md",
            "content": `**综合评级**\n${rating.finalGrade} 级"
          }
        },
        {
          "is_short": true,
          "text": {
            "tag": "lark_md",
            "content": `**综合得分**\n${rating.totalScore}/100"
          }
        }
      ]
    },
    {
      "tag": "hr"
    },
    {
      "tag": "div",
      "text": {
        "tag": "lark_md",
        "content": "**各维度评分**"
      }
    },
    // 收入
    {
      "tag": "div",
      "fields": [
        {
          "is_short": false,
          "text": {
            "tag": "lark_md",
            "content": `${metrics.revenue.emoji} **${metrics.revenue.label}** (权重${metrics.revenue.weight})\n数值: ${metrics.revenue.value}\n评级: ${metrics.revenue.grade} | 得分: ${metrics.revenue.score}"
          }
        }
      ]
    },
    // 活跃用户
    {
      "tag": "div",
      "fields": [
        {
          "is_short": false,
          "text": {
            "tag": "lark_md",
            "content": `${metrics.activeUsers.emoji} **${metrics.activeUsers.label}** (权重${metrics.activeUsers.weight})\n数值: ${metrics.activeUsers.value}\n评级: ${metrics.activeUsers.grade} | 得分: ${metrics.activeUsers.score}"
          }
        }
      ]
    },
    // 付费率
    {
      "tag": "div",
      "fields": [
        {
          "is_short": false,
          "text": {
            "tag": "lark_md",
            "content": `${metrics.payingRate.emoji} **${metrics.payingRate.label}** (权重${metrics.payingRate.weight})\n数值: ${metrics.payingRate.value}\n评级: ${metrics.payingRate.grade} | 得分: ${metrics.payingRate.score}"
          }
        }
      ]
    },
    // 留存率
    {
      "tag": "div",
      "fields": [
        {
          "is_short": false,
          "text": {
            "tag": "lark_md",
            "content": `${metrics.retention.emoji} **${metrics.retention.label}** (权重${metrics.retention.weight})\n数值: ${metrics.retention.value}\n评级: ${metrics.retention.grade} | 得分: ${metrics.retention.score}"
          }
        }
      ]
    },
    {
      "tag": "hr"
    },
    {
      "tag": "div",
      "text": {
        "tag": "lark_md",
        "content": `**补充信息**\n- 近30天交易笔数: ${additionalInfo.transactions.toLocaleString()}\n- 付费用户数: ${additionalInfo.payingUsers.toLocaleString()}\n- 总用户数: ${additionalInfo.totalUsers.toLocaleString()}\n- 平均交易额: ¥${additionalInfo.avgTransaction.toFixed(2)}"
      }
    },
    {
      "tag": "note",
      "elements": [
        {
          "tag": "plain_text",
          "content": `生成时间: ${new Date(generatedAt).toLocaleString('zh-CN')} | 统计周期: 近30天"
        }
      ]
    },
    {
      "tag": "action",
      "actions": [
        {
          "tag": "button",
          "text": {
            "tag": "plain_text",
            "content": "📥 下载详细报告"
          },
          "type": "primary",
          "url": "{{下载链接}}"
        }
      ]
    }
  ]
};

return {
  json: {
    card: card,
    gameName: gameName,
    rating: rating,
    metrics: metrics
  }
};

