// 错误处理
const error = $input.item;
const errorMessage = error.message || '未知错误';
const gameName = $node['Webhook触发']?.json?.body?.game_name || '未知游戏';

return {
  json: {
    success: false,
    error: errorMessage,
    gameName: gameName,
    timestamp: new Date().toISOString()
  }
};

